Binary Search (Answer).code:
int l = min_val, r = max_val;
while (l < r) {
    // [GOTCHA] 若更新邏輯是 l = mid，則計算 mid 需進位：l + (r - l + 1) / 2
    int mid = l + (r - l) / 2;
    if (check(mid)) {
        r = mid; // 尋找最小滿足條件者
    } else {
        l = mid + 1;
    }
}
return l;

Union-Find (DSU).code:
struct DSU {
    vector<int> p;
    DSU(int n) {
        p.resize(n);
        iota(p.begin(), p.end(), 0); // [GOTCHA] 記得初始化為 0 ~ n-1
    }
    int find(int i) {
        // [GOTCHA] 必須實作路徑壓縮 (Path Compression)
        return p[i] == i ? i : (p[i] = find(p[i]));
    }
    void unite(int i, int j) {
        int root_i = find(i), root_j = find(j);
        if (root_i != root_j) p[root_i] = root_j;
    }
};

Digit DP.code:
long long memo[20][2][2][state];
long long dfs(int pos, bool limit, bool lead, int s, string& num) {
    if (pos == num.size()) return 1;
    if (memo[pos][limit][lead][s] != -1) return memo[pos][limit][lead][s];

    int up = limit ? num[pos] - '0' : 9;
    long long res = 0;
    for (int i = 0; i <= up; i++) {
        // [GOTCHA] 1. 注意 limit 的傳遞邏輯
        // [GOTCHA] 2. lead zero (前導零) 可能影響計數狀態，依題意判斷
        res += dfs(pos + 1, limit && (i == up), lead && (i == 0), next_s, num);
    }
    return memo[pos][limit][lead][s] = res;
}

Segment Tree.code:
// [GOTCHA] 陣列空間建議開 4 * N
void build(int node, int start, int end) {
    if (start == end) {
        tree[node] = arr[start];
        return;
    }
    int mid = start + (end - start) / 2;
    build(2 * node, start, mid);
    build(2 * node + 1, mid + 1, end);
    tree[node] = max(tree[2 * node], tree[2 * node + 1]);
}
